    public void handleOrderBookSnapshot(Client client, Object message)
    {
        //
        // {
        //     "m": "depth",
        //     "symbol": "BTC/USDT",
        //     "data": {
        //       "ts": 1647520500149,
        //       "seqnum": 28590487626,
        //       "asks": [
        //         [Array], [Array], [Array],
        //         [Array], [Array], [Array],
        //       ],
        //       "bids": [
        //         [Array], [Array], [Array],
        //         [Array], [Array], [Array],
        //       ]
        //     }
        //   }
        //
        Object marketId = this.safeString(message, "symbol");
        Object symbol = this.safeSymbol(marketId);
        Object channel = this.safeString(message, "m");
        Object messageHash = Helpers.add(Helpers.add(channel, ":"), symbol);
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        Object data = this.safeValue(message, "data");
        Object snapshot = this.parseOrderBook(data, symbol);
        Helpers.addElementToObject(snapshot, "nonce", this.safeInteger(data, "seqnum"));
        Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
        // unroll the accumulated deltas
        Object messages = ((java.util.List<Object>)Helpers.GetValue(orderbook, "cache"));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messages)); i++)
        {
            Object messageItem = Helpers.GetValue(messages, i);
            this.handleOrderBookMessage(client, messageItem, orderbook);
        }
        Helpers.addElementToObject(this.orderbooks, symbol, orderbook);
        client.resolve(orderbook, messageHash);
    }

