    public Object handleOrderBookMessage(Client client, Object message, Object orderbook)
    {
        //
        // {
        //     "m":"depth",
        //     "symbol":"BTC/USDT",
        //     "data":{
        //        "ts":1647527417715,
        //        "seqnum":28590257013,
        //        "asks":[
        //           ["40990.47","0.01619"],
        //           ["41021.21","0"],
        //           ["41031.59","0.06096"]
        //        ],
        //        "bids":[
        //           ["40990.46","0.76114"],
        //           ["40985.18","0"]
        //        ]
        //     }
        //  }
        //
        Object data = this.safeValue(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object seqNum = this.safeInteger(data, "seqnum");
        if (Helpers.isTrue(Helpers.isGreaterThan(seqNum, Helpers.GetValue(orderbook, "nonce"))))
        {
            Object asks = this.safeValue(data, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object bids = this.safeValue(data, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            this.handleDeltas(Helpers.GetValue(orderbook, "asks"), asks);
            this.handleDeltas(Helpers.GetValue(orderbook, "bids"), bids);
            Helpers.addElementToObject(orderbook, "nonce", seqNum);
            Object timestamp = this.safeInteger(data, "ts");
            Helpers.addElementToObject(orderbook, "timestamp", timestamp);
            Helpers.addElementToObject(orderbook, "datetime", this.iso8601(timestamp));
        }
        return orderbook;
    }

